mapper.select:
SELECT FOLDER_ID
     , PARENT_FOLDER_ID
     , FOLDER_NAME
  FROM NAS_FOLDER
 WHERE FOLDER_ID = #{folderId}
   AND USER_CODE = #{userCode}

SELECT FP.STORAGE_PATH
     , FP.STORED_NAME
  FROM NAS_FILE F
  LEFT JOIN NAS_FILE_PREVIEW FP
    ON F.FILE_ID = FP.FILE_ID
 WHERE F.DELETE_YN = 'N'
   AND F.USER_CODE = #{userCode}
   AND F.FOLDER_ID = #{folderId}
   AND F.FILE_ID = #{fileId}

SELECT F.STORAGE_PATH
     , F.STORED_NAME
     , F.EXTENSION
  FROM NAS_FILE F
 WHERE F.DELETE_YN = 'N'
   AND F.USER_CODE = #{userCode}
   AND F.FOLDER_ID = #{folderId}
   AND F.FILE_ID = #{fileId}

mapper.update:
UPDATE NAS_FILE
   SET DELETE_YN = 'Y'
     , DELETED_AT = NOW()
 WHERE FILE_ID = #{fileId}
   AND FOLDER_ID = #{folderId}
   AND USER_CODE = #{userCode}
